"use client";
import { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '@/context/AuthContext';
import { CheckCircle, XCircle, Loader2, Eye, Edit3, Save, X, Bot, Image as ImageIcon, PlusCircle, LayoutList, CheckSquare } from 'lucide-react';
import { useRouter } from 'next/navigation';

export default function AdminPanel() {
  const { user, token } = useContext(AuthContext);
  const router = useRouter();

  const [pendingPosts, setPendingPosts] = useState([]);
  const [publishedPosts, setPublishedPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const [activeTab, setActiveTab] = useState('pending'); // 'pending' | 'published'
  const [previewPost, setPreviewPost] = useState(null);

  // סטייטים ליצירת פוסט ידני
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [newContent, setNewContent] = useState("");
  const [newCoverImage, setNewCoverImage] = useState("");
  const [newTags, setNewTags] = useState("");

  // סטייטים לעריכה
  const [editingPostId, setEditingPostId] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const [editContent, setEditContent] = useState("");
  const [editCoverImage, setEditCoverImage] = useState("");

  useEffect(() => {
    if (!token && !user) { setLoading(false); return; }
    if (user && user.role !== 'admin') { router.push('/'); return; }

    const fetchAllPosts = async () => {
      try {
        // מושכים גם את הממתינים וגם את המפורסמים במקביל
        const [pendingRes, publishedRes] = await Promise.all([
          axios.get(`${process.env.NEXT_PUBLIC_API_URL}/posts/pending`, { headers: { Authorization: `Bearer ${token}` } }),
          axios.get(`${process.env.NEXT_PUBLIC_API_URL}/posts/published`)
        ]);
        setPendingPosts(pendingRes.data);
        setPublishedPosts(publishedRes.data);
      } catch (error) {
        console.error("שגיאה במשיכת פוסטים:", error);
      } finally {
        setLoading(false);
      }
    };

    if (token) fetchAllPosts();
  }, [user, token, router]);

  // פונקציית יצירת פוסט ידני על ידי האדמין
  const handleCreatePost = async (e) => {
    e.preventDefault();
    if (!newTitle.trim() || !newContent.trim()) return alert("חובה למלא כותרת ותוכן!");
    const tagsArray = newTags.split(',').map(tag => tag.trim()).filter(t => t !== "");

    try {
      // 1. יצירת הפוסט
      const createRes = await axios.post(`${process.env.NEXT_PUBLIC_API_URL}/posts`, 
        { title: newTitle, content: newContent, coverImage: newCoverImage, tags: tagsArray, authorAgent: 'Admin (Manual)' }
      );
      
      const newPostId = createRes.data.post._id;

      // 2. פרסום מיידי של הפוסט (שינוי סטטוס ל-published)
      await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/posts/${newPostId}/status`,
        { status: 'published' },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      // 3. עדכון המסך והעברה ללשונית "באוויר"
      setPublishedPosts([{ ...createRes.data.post, status: 'published' }, ...publishedPosts]);
      setNewTitle(""); setNewContent(""); setNewCoverImage(""); setNewTags("");
      setShowCreateForm(false);
      setActiveTab('published');
    } catch (error) {
      console.error("שגיאה ביצירת פוסט מנהל:", error);
      alert("שגיאה ביצירת הפוסט.");
    }
  };

  const handleStatusUpdate = async (id, newStatus) => {
    try {
      await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/posts/${id}/status`,
        { status: newStatus },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      // עדכון רשימות הפוסטים בהתאם לסטטוס
      if (activeTab === 'pending') {
        const postToMove = pendingPosts.find(p => p._id === id);
        setPendingPosts(prev => prev.filter(p => p._id !== id));
        if (newStatus === 'published' && postToMove) setPublishedPosts([{...postToMove, status: 'published'}, ...publishedPosts]);
      } else {
        // אם אנחנו מסירים פוסט מלשונית "באוויר"
        setPublishedPosts(prev => prev.filter(p => p._id !== id));
      }
      setPreviewPost(null);
    } catch (error) {
      alert('שגיאה בעדכון הסטטוס.');
    }
  };

  const startEditing = (post) => {
    setEditingPostId(post._id);
    setEditTitle(post.title);
    setEditContent(post.content);
    setEditCoverImage(post.coverImage || "");
  };

  const handleUpdatePost = async (id) => {
    try {
      await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/posts/${id}`,
        { title: editTitle, content: editContent, coverImage: editCoverImage },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      // מעדכנים גם בממתינים וגם במפורסמים כדי לכסות את כל המצבים
      const updateFn = posts => posts.map(p => p._id === id ? { ...p, title: editTitle, content: editContent, coverImage: editCoverImage } : p);
      setPendingPosts(updateFn);
      setPublishedPosts(updateFn);
      setEditingPostId(null);
    } catch (error) {
      alert("שגיאה בשמירת השינויים.");
    }
  };

  if (loading) return <div className="flex justify-center items-center min-h-screen"><Loader2 className="w-12 h-12 animate-spin text-indigo-500" /></div>;
  if (!user || user.role !== 'admin') return <div className="min-h-screen flex items-center justify-center text-rose-500">אין הרשאה.</div>;

  const currentPosts = activeTab === 'pending' ? pendingPosts : publishedPosts;

  return (
    <main className="min-h-screen bg-slate-50 py-12 px-4 md:px-8 relative">
      <div className="max-w-5xl mx-auto">
        
        {/* כותרת וכפתור יצירה */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">
            פאנל ניהול <span className="text-rose-500">תוכן המערכת</span>
          </h1>
          <button 
            onClick={() => setShowCreateForm(!showCreateForm)}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-3 rounded-xl flex items-center gap-2 transition shadow-sm font-medium"
          >
            <PlusCircle className="w-5 h-5" /> {showCreateForm ? 'ביטול יצירה' : 'פוסט רשמי חדש'}
          </button>
        </div>

        {/* טופס יצירת פוסט ידני */}
        {showCreateForm && (
          <form onSubmit={handleCreatePost} className="bg-white p-6 rounded-2xl shadow-sm border border-indigo-100 mb-8 animation-fade-in">
            <h2 className="text-xl font-bold mb-4 text-slate-800 flex items-center gap-2"><Edit3 className="w-5 h-5 text-indigo-500"/> כתיבת כתבה חדשה (תפורסם מיידית)</h2>
            <input type="text" placeholder="כותרת הכתבה..." className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 mb-4 focus:ring-2 focus:ring-indigo-500 outline-none transition" value={newTitle} onChange={(e) => setNewTitle(e.target.value)} />
            
            <div className="flex flex-col gap-2 mb-4">
              <label className="text-sm font-bold text-slate-700">קישור לתמונה (URL)</label>
              <input type="text" placeholder="https://example.com/image.jpg" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 outline-none transition text-left dir-ltr" value={newCoverImage} onChange={(e) => setNewCoverImage(e.target.value)} />
              {newCoverImage && <img src={newCoverImage} alt="Preview" className="h-32 w-64 object-cover rounded-lg border border-slate-200 mt-2" onError={(e) => e.target.style.display='none'} />}
            </div>

            <textarea placeholder="תוכן הכתבה..." rows="6" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 mb-4 focus:ring-2 focus:ring-indigo-500 outline-none transition resize-none" value={newContent} onChange={(e) => setNewContent(e.target.value)}></textarea>
            <input type="text" placeholder="תגיות (מופרדות בפסיקים)" className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 mb-6 focus:ring-2 focus:ring-indigo-500 outline-none transition text-sm" value={newTags} onChange={(e) => setNewTags(e.target.value)} />
            <button type="submit" className="w-full bg-emerald-500 hover:bg-emerald-600 text-white font-bold py-3 rounded-xl transition shadow-sm">פרסם לאתר</button>
          </form>
        )}

        {/* לשוניות ניווט */}
        <div className="flex border-b border-slate-200 mb-6">
          <button 
            onClick={() => setActiveTab('pending')} 
            className={`flex items-center gap-2 px-6 py-4 font-bold text-lg transition-colors border-b-4 ${activeTab === 'pending' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <LayoutList className="w-5 h-5" /> ממתינים לאישור ({pendingPosts.length})
          </button>
          <button 
            onClick={() => setActiveTab('published')} 
            className={`flex items-center gap-2 px-6 py-4 font-bold text-lg transition-colors border-b-4 ${activeTab === 'published' ? 'border-emerald-500 text-emerald-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
            <CheckSquare className="w-5 h-5" /> באוויר ({publishedPosts.length})
          </button>
        </div>
        
        {/* רשימת הפוסטים */}
        {currentPosts.length === 0 ? (
          <div className="bg-white p-10 rounded-2xl shadow-sm text-center border border-slate-100">
            <p className="text-xl text-slate-500">אין פוסטים להציג בלשונית זו כרגע.</p>
          </div>
        ) : (
          <div className="flex flex-col gap-6">
            {currentPosts.map(post => (
              <div key={post._id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-6 items-start relative overflow-hidden">
                
                {/* סרט סימון לסטטוס */}
                {activeTab === 'published' && <div className="absolute top-0 right-0 bg-emerald-500 text-white text-xs font-bold px-3 py-1 rounded-bl-lg">לייב באתר</div>}

                {post.coverImage && !editingPostId && (
                  <img src={post.coverImage} alt={post.title} className="w-full md:w-48 h-32 object-cover rounded-xl border border-slate-100" />
                )}
                
                <div className="flex-grow w-full mt-2">
                  {editingPostId === post._id ? (
                    <div className="flex flex-col gap-4 w-full">
                      <input type="text" value={editTitle} onChange={(e) => setEditTitle(e.target.value)} className="text-xl font-bold bg-slate-50 border border-slate-200 rounded-lg px-4 py-2" />
                      
                      <div className="flex flex-col gap-2">
                        <label className="text-sm font-bold text-slate-700 flex items-center gap-1"><ImageIcon className="w-4 h-4"/> קישור תמונה</label>
                        <input type="text" value={editCoverImage} onChange={(e) => setEditCoverImage(e.target.value)} className="bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 dir-ltr text-left" />
                        {editCoverImage && <img src={editCoverImage} className="h-24 w-48 object-cover rounded border" onError={(e)=>e.target.style.display='none'}/>}
                      </div>

                      <textarea value={editContent} onChange={(e) => setEditContent(e.target.value)} rows="5" className="bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 resize-none" />
                      <div className="flex gap-2 justify-end">
                        <button onClick={() => setEditingPostId(null)} className="px-4 py-2 text-slate-500 bg-slate-100 rounded-xl hover:bg-slate-200">ביטול</button>
                        <button onClick={() => handleUpdatePost(post._id)} className="px-5 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700">שמור</button>
                      </div>
                    </div>
                  ) : (
                    <>
                      <h2 className="text-xl font-bold text-slate-800 mb-1">{post.title}</h2>
                      {post.sourceUrl && (
                        <a 
                          href={post.sourceUrl} 
                          target="_blank" 
                          rel="noopener noreferrer" 
                          className="inline-block mb-4 text-sm font-bold text-indigo-600 hover:text-indigo-800 underline"
                        >
                          🔗 צפה בכתבה המקורית באנגלית
                        </a>
                      )}
                      <p className="text-slate-600 mb-4 line-clamp-2 text-sm">{post.content}</p>
                      
                      <div className="flex flex-wrap gap-2">
                        {activeTab === 'pending' && (
                          <button onClick={() => handleStatusUpdate(post._id, 'published')} className="flex items-center gap-1 bg-emerald-50 text-emerald-600 px-3 py-1.5 rounded-lg hover:bg-emerald-100 text-sm font-bold">
                            <CheckCircle className="w-4 h-4" /> אשר ופרסם
                          </button>
                        )}
                        <button onClick={() => setPreviewPost(post)} className="flex items-center gap-1 bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-lg hover:bg-indigo-100 text-sm font-bold">
                          <Eye className="w-4 h-4" /> תצוגה
                        </button>
                        <button onClick={() => startEditing(post)} className="flex items-center gap-1 bg-slate-100 text-slate-700 px-3 py-1.5 rounded-lg hover:bg-slate-200 text-sm font-bold">
                          <Edit3 className="w-4 h-4" /> ערוך
                        </button>
                        <button onClick={() => handleStatusUpdate(post._id, 'rejected')} className="flex items-center gap-1 bg-rose-50 text-rose-600 px-3 py-1.5 rounded-lg hover:bg-rose-100 text-sm font-bold ml-auto">
                          <XCircle className="w-4 h-4" /> {activeTab === 'published' ? 'מחק מהאתר' : 'דחה'}
                        </button>
                      </div>
                    </>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* תצוגה מקדימה מלאה (Modal) */}
      {previewPost && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex justify-center items-center p-4 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-hidden my-8 relative flex flex-col max-h-[90vh]">
            <button onClick={() => setPreviewPost(null)} className="absolute top-4 right-4 bg-black/50 hover:bg-black/70 text-white p-2 rounded-full transition z-10"><X className="w-6 h-6" /></button>
            <div className="overflow-y-auto flex-grow">
              {previewPost.coverImage && <img src={previewPost.coverImage} alt={previewPost.title} className="w-full h-64 md:h-80 object-cover" />}
              <div className="p-8 md:p-12">
                <h1 className="text-3xl md:text-5xl font-black text-slate-900 mb-6">{previewPost.title}</h1>
                <p className="text-lg text-slate-700 whitespace-pre-wrap">{previewPost.content}</p>
              </div>
            </div>
          </div>
        </div>
      )}
    </main>
  );
}